  1	import * as React from 'react';
  2	import classNames from 'classnames';
  3	import { useTranslation } from 'react-i18next';
  4	import {
  5	  Alert,
  6	  Card,
  7	  CardBody,
  8	  Grid,
  9	  GridItem,
 10	  ToggleGroup,
 11	  ToggleGroupItem,
 12	} from '@patternfly/react-core';
 13	import { useFlag } from '@openshift-console/dynamic-plugin-sdk';
 14	import PipelineRunsForRepositoriesList from './PipelineRunsForRepositoriesList';
 15	import PipelineRunsForPipelinesList from './PipelineRunsForPipelinesList';
 16	import SearchInputField from '../SearchInput';
 17	import { SummaryProps, useInterval, useQueryParams } from '../utils';
 18	import { getResultsSummary } from '../../../components/utils/summary-api';
 19	import { DataType, FLAGS } from '../../../types';
 20	import { getDropDownDate } from '../dateTime';
 21	import { ALL_NAMESPACES_KEY } from '../../../consts';
 22	
 23	type PipelineRunsListPageProps = {
 24	  bordered?: boolean;
 25	  namespace: string;
 26	  timespan: number;
 27	  interval: number;
 28	};
 29	
 30	const PipelineRunsListPage: React.FC<PipelineRunsListPageProps> = ({
 31	  bordered,
 32	  namespace,
 33	  timespan,
 34	  interval,
 35	}) => {
 36	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 37	  const isDevConsoleProxyAvailable = useFlag(FLAGS.DEVCONSOLE_PROXY);
 38	
 39	  const [pageFlag, setPageFlag] = React.useState(1);
 40	  const [loaded, setloaded] = React.useState(false);
 41	  const [pipelineRunsListError, setPipelineRunsListError] = React.useState<
 42	    string | undefined
 43	  >();
 44	  const [summaryData, setSummaryData] = React.useState<SummaryProps[]>([]);
 45	  const [searchText, setSearchText] = React.useState('');
 46	  const [summaryDataFiltered, setSummaryDataFiltered] = React.useState<
 47	    SummaryProps[]
 48	  >([]);
 49	  const abortControllerRef = React.useRef<AbortController>();
 50	
 51	  const date = getDropDownDate(timespan).toISOString();
 52	  if (namespace == ALL_NAMESPACES_KEY) {
 53	    namespace = '-';
 54	  }
 55	
 56	  React.useEffect(() => {
 57	    return () => {
 58	      abortControllerRef.current?.abort();
 59	    };
 60	  }, []);
 61	
 62	  const getSummaryData = () => {
 63	    abortControllerRef.current?.abort();
 64	    abortControllerRef.current = new AbortController();
 65	
 66	    // Clear stale data before making new request
 67	    setSummaryData([]);
 68	    setSummaryDataFiltered([]);
 69	
 70	    setPipelineRunsListError(undefined);
 71	    setloaded(false);
 72	    getResultsSummary(
 73	      namespace,
 74	      pageFlag === 1
 75	        ? {
 76	            summary: 'total_duration,avg_duration,total,succeeded,last_runtime',
 77	            data_type: DataType?.PipelineRun,
 78	            groupBy: 'pipeline',
 79	            filter: `data.status.startTime>timestamp("${date}") && data.spec.pipelineRef.contains("name")`,
 80	          }
 81	        : {
 82	            summary: 'total_duration,avg_duration,total,succeeded,last_runtime',
 83	            data_type: DataType?.PipelineRun,
 84	            groupBy: 'repository',
 85	            filter: `data.status.startTime>timestamp("${date}") && data.metadata.labels.contains('pipelinesascode.tekton.dev/repository')`,
 86	          },
 87	      undefined,
 88	      isDevConsoleProxyAvailable,
 89	      abortControllerRef.current.signal,
 90	      90000,
 91	    )
 92	      .then((response) => {
 93	        setloaded(true);
 94	        setPipelineRunsListError(undefined);
 95	        setSummaryData((response?.summary || []) ?? []);
 96	        setSummaryDataFiltered((response?.summary || []) ?? []);
 97	      })
 98	      .catch((e) => {
 99	        if (e.name === 'AbortError') {
100	          // Request was cancelled, this is expected behavior
101	          return;
102	        }
103	        setloaded(true);
104	        setPipelineRunsListError(
105	          e.message || t('Failed to load pipeline runs list'),
106	        );
107	        // Keep data cleared on error to prevent stale data display
108	        setSummaryData([]);
109	        setSummaryDataFiltered([]);
110	      });
111	  };
112	
113	  useInterval(getSummaryData, interval, namespace, date, pageFlag);
114	
115	  React.useEffect(() => {
116	    setloaded(false);
117	    setPipelineRunsListError(undefined);
118	    setSummaryData([]);
119	    setSummaryDataFiltered([]);
120	  }, [namespace, timespan]);
121	
122	  useQueryParams({
123	    key: 'search',
124	    value: searchText,
125	    setValue: setSearchText,
126	    defaultValue: '',
127	  });
128	
129	  useQueryParams({
130	    key: 'list',
131	    value: pageFlag,
132	    setValue: setPageFlag,
133	    defaultValue: 1,
134	    options: { perpipeline: 1, perrepository: 2 },
135	    displayFormat: (v) => (v == 1 ? 'perpipeline' : 'perrepository'),
136	    loadFormat: (v) => (v == 'perrepository' ? 2 : 1),
137	  });
138	
139	  const handlePageChange = (pageNumber: number) => {
140	    setloaded(false);
141	    setPipelineRunsListError(undefined);
142	    setSummaryData([]);
143	    setSummaryDataFiltered([]);
144	    setPageFlag(pageNumber);
145	  };
146	  const handleNameChange = (value: string) => {
147	    setSearchText(value);
148	    const filteredData = summaryData.filter((summary) =>
149	      summary.group_value
150	        .split('/')[1]
151	        .toLowerCase()
152	        .includes(value.toLowerCase()),
153	    );
154	    setSummaryDataFiltered(filteredData);
155	  };
156	  return (
157	    <Card
158	      className={classNames('pipeline-overview__pipelinerun-status-card', {
159	        'card-border': bordered,
160	      })}
161	    >
162	      <CardBody>
163	        {pipelineRunsListError ? (
164	          <Alert
165	            variant="danger"
166	            isInline
167	            title={t('Unable to load pipeline runs list')}
168	            className="pf-v6-u-mb-md"
169	          />
170	        ) : (
171	          <>
172	            <Grid hasGutter className="pipeline-overview__listpage__grid">
173	              <GridItem
174	                span={9}
175	                className="pipeline-overview__listpage__griditem"
176	              >
177	                {/* Lastrun Status is not provided by API  */}
178	                {/* <StatusDropdown /> */}
179	                <SearchInputField
180	                  searchText={searchText}
181	                  pageFlag={pageFlag}
182	                  handleNameChange={handleNameChange}
183	                />
184	              </GridItem>
185	              <GridItem span={3}>
186	                <ToggleGroup className="pipeline-overview__listpage__button">
187	                  <ToggleGroupItem
188	                    text={t('Per Pipeline')}
189	                    buttonId="pipelineButton"
190	                    isSelected={pageFlag === 1}
191	                    onChange={() => handlePageChange(1)}
192	                  />
193	                  <ToggleGroupItem
194	                    text={t('Per Repository')}
195	                    buttonId="repositoryButton"
196	                    isSelected={pageFlag === 2}
197	                    onChange={() => handlePageChange(2)}
198	                  />
199	                </ToggleGroup>
200	              </GridItem>
201	            </Grid>
202	            <Grid hasGutter>
203	              <GridItem span={12}>
204	                {pageFlag === 1 ? (
205	                  <PipelineRunsForPipelinesList
206	                    summaryData={summaryData}
207	                    summaryDataFiltered={summaryDataFiltered}
208	                    loaded={loaded}
209	                  />
210	                ) : (
211	                  <PipelineRunsForRepositoriesList
212	                    summaryData={summaryData}
213	                    summaryDataFiltered={summaryDataFiltered}
214	                    loaded={loaded}
215	                  />
216	                )}
217	              </GridItem>
218	            </Grid>
219	          </>
220	        )}
221	      </CardBody>
222	    </Card>
223	  );
224	};
225	
226	export default PipelineRunsListPage;

